import './TableData.scss';

import { Tooltip } from ':components/Tooltip';
import { classNames } from ':helpers/classnames';
import type { FC } from 'react';
import React, { forwardRef } from 'react';

import type { TableDataProps } from './TableData.types';

export const TableData: FC<TableDataProps> = ({
	dense = false,
	alignRight = false,
	horizontalAlign,
	verticalAlign,
	className,
	hoverText,
	expandable,
	children,
	depth,
	...props
}) => {
	if (alignRight) {
		// eslint-disable-next-line no-console
		console.warn('Свойство alignRight устарело, используйте horizontalAlign="right"');
	}

	// eslint-disable-next-line id-length
	const CellValue: FC = forwardRef<HTMLDivElement>((_, ref) => (
		<div ref={ref} className="dsb_table-cell__content">
			{children}
		</div>
	));

	const indentStyle = depth ? { paddingLeft: `calc(16px * ${depth})` } : undefined;

	return (
		<td
			data-testid="TableData"
			{...props}
			style={indentStyle}
			className={classNames(
				'dsb_table-cell',
				dense && 'dsb_table-cell__dense',
				alignRight && !horizontalAlign && 'dsb_table-cell__horizontal-align-right',
				horizontalAlign && `dsb_table-cell__horizontal-align-${horizontalAlign}`,
				verticalAlign && `dsb_table-cell__vertical-align-${verticalAlign}`,
				expandable && 'dsb_table-cell__expandable',
				Boolean(depth) && `dsb_table-cell__depth-${depth}`,
				className,
			)}
		>
			{hoverText ? (
				<div className={classNames('dsb_table-cell_flex', alignRight && 'dsb_table-cell__align-right')}>
					<Tooltip title={hoverText}>
						<CellValue></CellValue>
					</Tooltip>
				</div>
			) : (
				<div className={classNames('dsb_table-cell_flex', alignRight && 'dsb_table-cell__align-right')}>
					{/* дополнительный блочный див, так как во flex не работает 	text-overflow: ellipsis; */}
					<div className="dsb_table-cell__content">{children}</div>
				</div>
			)}
		</td>
	);
};
